$(document).ready(function(){const fullscreenContainer=$('#fullscreen-overlay');let startX=0;const minSwipeDistance=120;function openFullscreen(imageElement){const swipeUrl=imageElement.data('swipe-url');const pk=imageElement.data('pk');const isVideo=imageElement.data('is-video');htmx.ajax('GET',swipeUrl+"#image",{target:'#swipe-container'});fullscreenContainer.css('display','flex').hide().fadeIn(300);};function executeSwipe(side,diff=null){console.log("executeSwipe",side);const container=$('#image-container');const pk=container.data('pk');const url=container.attr('hx-get');const angle=diff?-diff/15:(side==='prev'?-60:60);const sign=side==='prev'?'-':'';if(url){container.css({'transform':`translateX(${sign}150%)rotate(${angle}deg)`,'opacity':'0'});htmx.ajax('GET',url,{target:'#swipe-container',values:{side:side}});}};$(document).on('touchstart','#image-container',function(e){startX=e.originalEvent.touches[0].pageX;$(this).css('transition','none');});$(document).on('touchmove','#image-container',function(e){const currentX=e.originalEvent.touches[0].pageX;let diff=currentX-startX;$(this).css('transform',`translateX(${diff}px)rotate(${diff/15}deg)`);});$(document).on('touchend','#image-container',function(e){const currentX=e.originalEvent.changedTouches[0].pageX;const diff=currentX-startX;if(diff>minSwipeDistance){setTimeout(()=>executeSwipe("prev",diff),20);}else if(diff<-minSwipeDistance){setTimeout(()=>executeSwipe("next",diff),20);}else{$(this).css('transform','translateX(0) rotate(0)');};startX=0;});$('.gallery-image').click(function(){openFullscreen($(this));});$('#prev-image').click(function(){console.log("prev-image");setTimeout(()=>executeSwipe("prev"),20);});$('#next-image').click(function(){console.log("next-image");setTimeout(()=>executeSwipe("next"),20);});$('#close-fullscreen').click(function(){fullscreenContainer.fadeOut(300);fullscreenContainer.find('#image-container').html('');});fullscreenContainer.find('div[class="image-container"]').click(function(e){if(e.target===e.currentTarget){fullscreenContainer.fadeOut(300);fullscreenContainer.find('#image-container').html('');}});const urlParams=new URLSearchParams(window.location.search);if(urlParams.get('openFullscreen')==='true'){openFullscreen($(`.gallery-image[data-fullscreen="${urlParams.get('firstImage')}"]`));};let slideshowTimer=null;const slideshowDelay=(parseInt($('#slideshow-toggle').data('delay'))||5)*1000;function startSlideshowTimer(){stopSlideshowTimer();slideshowTimer=setTimeout(function(){executeSwipe("next");},slideshowDelay);};function stopSlideshowTimer(){if(slideshowTimer){clearTimeout(slideshowTimer);slideshowTimer=null;}};function toggleSlideshow(){const btn=$('#slideshow-toggle');const icon=$('#slideshow-icon');const fullscreenBtn=$('#fullscreen-slideshow-toggle');const fullscreenIcon=$('#fullscreen-slideshow-icon');const isActive=btn.hasClass('is-active');if(isActive){btn.removeClass('is-active');icon.removeClass('mdi-pause').addClass('mdi-play');fullscreenBtn.removeClass('is-active');fullscreenIcon.removeClass('mdi-pause').addClass('mdi-play');stopSlideshowTimer();}else{btn.addClass('is-active');icon.removeClass('mdi-play').addClass('mdi-pause');fullscreenBtn.addClass('is-active');fullscreenIcon.removeClass('mdi-play').addClass('mdi-pause');if(fullscreenContainer.css('display')==='none'){const firstImage=$('.gallery-image').first();if(firstImage.length>0){openFullscreen(firstImage);}};startSlideshowTimer();}};$('#slideshow-toggle, #fullscreen-slideshow-toggle').click(function(e){e.stopPropagation();toggleSlideshow();});function syncFullscreenButton(){const isActive=$('#slideshow-toggle').hasClass('is-active');const fullscreenIcon=$('#fullscreen-slideshow-icon');const fullscreenBtn=$('#fullscreen-slideshow-toggle');if(isActive){fullscreenBtn.addClass('is-active');fullscreenIcon.removeClass('mdi-play').addClass('mdi-pause');}else{fullscreenBtn.removeClass('is-active');fullscreenIcon.removeClass('mdi-pause').addClass('mdi-play');}};$(document).on('click','.gallery-image',function(){syncFullscreenButton();});$(document).on('htmx:afterOnLoad',function(evt){if(evt.detail.target.id==='swipe-container'&&$('#slideshow-toggle').hasClass('is-active')){startSlideshowTimer();}});$('#prev-image, #next-image').click(function(){if($('#slideshow-toggle').hasClass('is-active')){startSlideshowTimer();}});$('#close-fullscreen').click(function(){if($('#slideshow-toggle').hasClass('is-active')){toggleSlideshow();}});});